const clamp = (value: number, min: number, max: number) => Math.max(min, Math.min(max, value));
const clamp01 = (value: number) => clamp(value, 0, 1);

const progress = (timeline: number, start: number, end: number) =>
  interpolate(timeline, [start, end], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.inOut(Easing.cubic),
  });

const lifecycle = (
  timeline: number,
  start: number,
  end: number,
  exitStart = 838,
  exitEnd = 900,
) => Math.min(progress(timeline, start, end), 1 - progress(timeline, exitStart, exitEnd));

const trillions = (value: number) => `$${value.toFixed(value < 1 ? 2 : 2)}T`;
const billions = (value: number) => `$${value.toFixed(0)}B`;

const normalize = (v: Vec3): Vec3 => {
  const length = Math.hypot(v[0], v[1], v[2]) || 1;
  return [v[0] / length, v[1] / length, v[2] / length];
};

const lonLatToWorld = ([lon, lat]: LonLat): Vec3 => {
  const lambda = lon * DEG;
  const phi = lat * DEG;
  const cosPhi = Math.cos(phi);
  return [cosPhi * Math.sin(lambda), Math.sin(phi), cosPhi * Math.cos(lambda)];
};

const worldToCamera = (world: Vec3, camera: GlobeCamera): Vec3 => {
  const yaw = camera.centerLon * DEG;
  const pitch = camera.centerLat * DEG;
  const cosYaw = Math.cos(yaw);
  const sinYaw = Math.sin(yaw);
  const cosPitch = Math.cos(pitch);
  const sinPitch = Math.sin(pitch);
  const x = world[0] * cosYaw - world[2] * sinYaw;
  const zYaw = world[0] * sinYaw + world[2] * cosYaw;
  return [x, cosPitch * world[1] - sinPitch * zYaw, sinPitch * world[1] + cosPitch * zYaw];
};

const cameraVector = (coordinate: LonLat, camera: GlobeCamera): Vec3 =>
  worldToCamera(lonLatToWorld(coordinate), camera);

const projectVector = (v: Vec3, cx: number, cy: number, radius: number) => ({
  x: cx + radius * v[0],
  y: cy - radius * v[1],
  z: v[2],
});

const projectOrthographic = (coordinate: LonLat, camera: GlobeCamera, cx: number, cy: number, radius: number) =>
  projectVector(cameraVector(coordinate, camera), cx, cy, radius);

const horizonIntersection = (a: Vec3, b: Vec3): Vec3 => {
  const t = a[2] / (a[2] - b[2]);
  return normalize([a[0] + (b[0] - a[0]) * t, a[1] + (b[1] - a[1]) * t, 0]);
};

const svgPoint = (v: Vec3, cx: number, cy: number, radius: number) => {
  const p = projectVector(v, cx, cy, radius);
  return `${p.x.toFixed(1)},${p.y.toFixed(1)}`;
};

const projectedLinePath = (
  lines: readonly (readonly LonLat[])[],
  camera: GlobeCamera,
  cx: number,
  cy: number,
  radius: number,
) => {
  const commands: string[] = [];
  for (const line of lines) {
    if (line.length < 2) continue;
    let a = cameraVector(line[0], camera);
    let open = false;
    for (let index = 1; index < line.length; index++) {
      const b = cameraVector(line[index], camera);
      const aVisible = a[2] >= 0;
      const bVisible = b[2] >= 0;
      if (aVisible && bVisible) {
        if (!open) commands.push(`M${svgPoint(a, cx, cy, radius)}`);
        commands.push(`L${svgPoint(b, cx, cy, radius)}`);
        open = true;
      } else if (aVisible && !bVisible) {
        if (!open) commands.push(`M${svgPoint(a, cx, cy, radius)}`);
        commands.push(`L${svgPoint(horizonIntersection(a, b), cx, cy, radius)}`);
        open = false;
      } else if (!aVisible && bVisible) {
        commands.push(`M${svgPoint(horizonIntersection(a, b), cx, cy, radius)}`);
        commands.push(`L${svgPoint(b, cx, cy, radius)}`);
        open = true;
      } else open = false;
      a = b;
    }
  }
  return commands.join('');
};

const projectedDotBands = (
  points: readonly LonLat[],
  camera: GlobeCamera,
  cx: number,
  cy: number,
  radius: number,
) => {
  const bands: string[][] = [[], [], []];
  for (const coordinate of points) {
    const v = cameraVector(coordinate, camera);
    if (v[2] <= 0) continue;
    const point = projectVector(v, cx, cy, radius);
    const band = Math.min(2, Math.floor(v[2] * 3));
    bands[band].push(`M${point.x.toFixed(1)},${point.y.toFixed(1)}h.01`);
  }
  return [bands[0].join(''), bands[1].join(''), bands[2].join('')] as const;
};

const GLOBE_GRATICULE: readonly (readonly LonLat[])[] = [
  ...Array.from({length: 12}, (_, index) => -180 + index * 30).map((lon) =>
    Array.from({length: 81}, (_, index) => [lon, -80 + index * 2] as const),
  ),
  ...[-60, -30, 0, 30, 60].map((lat) =>
    Array.from({length: 121}, (_, index) => [-180 + index * 3, lat] as const),
  ),
] as const;

const slerpUnit = (from: Vec3, to: Vec3, t: number): Vec3 => {
  const dot = clamp(from[0] * to[0] + from[1] * to[1] + from[2] * to[2], -1, 1);
  const omega = Math.acos(dot);
  const sinOmega = Math.sin(omega);
  if (Math.abs(sinOmega) < 1e-6) return normalize([
    from[0] + (to[0] - from[0]) * t,
    from[1] + (to[1] - from[1]) * t,
    from[2] + (to[2] - from[2]) * t,
  ]);
  const a = Math.sin((1 - t) * omega) / sinOmega;
  const b = Math.sin(t * omega) / sinOmega;
  return [from[0] * a + to[0] * b, from[1] * a + to[1] * b, from[2] * a + to[2] * b];
};

const raisedRouteCameraPoint = (from: LonLat, to: LonLat, t: number, camera: GlobeCamera, height: number): Vec3 => {
  const surface = slerpUnit(lonLatToWorld(from), lonLatToWorld(to), t);
  const lift = 1 + height * Math.sin(Math.PI * t);
  return worldToCamera([surface[0] * lift, surface[1] * lift, surface[2] * lift], camera);
};

const routePointVisible = (v: Vec3) => {
  const screenRadius2 = v[0] * v[0] + v[1] * v[1];
  if (screenRadius2 >= 1) return true;
  return v[2] >= Math.sqrt(Math.max(0, 1 - screenRadius2)) - 1e-5;
};

const greatCircleArcPath = (
  from: LonLat,
  to: LonLat,
  camera: GlobeCamera,
  cx: number,
  cy: number,
  radius: number,
  height = .18,
  samples = 54,
) => {
  const commands: string[] = [];
  let previousT = 0;
  let previous = raisedRouteCameraPoint(from, to, 0, camera, height);
  let previousVisible = routePointVisible(previous);
  let open = false;
  for (let index = 1; index <= samples; index++) {
    const t = index / samples;
    const current = raisedRouteCameraPoint(from, to, t, camera, height);
    const currentVisible = routePointVisible(current);
    let boundary: Vec3 | null = null;
    if (previousVisible !== currentVisible) {
      let low = previousT;
      let high = t;
      for (let step = 0; step < 7; step++) {
        const middle = (low + high) / 2;
        const sample = raisedRouteCameraPoint(from, to, middle, camera, height);
        if (routePointVisible(sample) === previousVisible) low = middle;
        else high = middle;
      }
      boundary = raisedRouteCameraPoint(from, to, (low + high) / 2, camera, height);
    }
    if (previousVisible && currentVisible) {
      if (!open) commands.push(`M${svgPoint(previous, cx, cy, radius)}`);
      commands.push(`L${svgPoint(current, cx, cy, radius)}`);
      open = true;
    } else if (previousVisible && !currentVisible && boundary) {
      if (!open) commands.push(`M${svgPoint(previous, cx, cy, radius)}`);
      commands.push(`L${svgPoint(boundary, cx, cy, radius)}`);
      open = false;
    } else if (!previousVisible && currentVisible && boundary) {
      commands.push(`M${svgPoint(boundary, cx, cy, radius)}`);
      commands.push(`L${svgPoint(current, cx, cy, radius)}`);
      open = true;
    } else open = false;
    previousT = t;
    previous = current;
    previousVisible = currentVisible;
  }
  return commands.join('');
};

const routeBeadAt = (
  from: LonLat,
  to: LonLat,
  routeProgress: number,
  camera: GlobeCamera,
  cx: number,
  cy: number,
  radius: number,
  height = .18,
) => {
  const point = raisedRouteCameraPoint(from, to, ((routeProgress % 1) + 1) % 1, camera, height);
  return {...projectVector(point, cx, cy, radius), visible: routePointVisible(point)};
};

const regionColor = (region: RegionKey) => REGIONS.find((item) => item.key === region)?.color ?? C.cyan;
const findHub = (city: string) => HUBS.find((hub) => hub.city === city) ?? HUBS[0];

const globeCameraAt = (timeline: number, phase: number): GlobeCamera => {
  return {
    centerLon: -28 + 360 * (timeline / 900),
    centerLat: 12 + Math.sin(phase) * 3.2,
  };
};

