const trendPoint = (index: number, value: number) => ({
  x: 300 + index * 180,
  y: 82 - ((value - 50) / 40) * 58,
});

const trendPath = REVENUE_TREND.map((value, index) => {
  const point = trendPoint(index, value);
  return `${index === 0 ? 'M' : 'L'}${point.x},${point.y}`;
}).join(' ');

const trendArea = `${trendPath} L${trendPoint(6, REVENUE_TREND[6]).x},89 L${trendPoint(0, REVENUE_TREND[0]).x},89 Z`;

