const Ambient: React.FC<{phase: number}> = ({phase}) => {
  const dots = Array.from({length: 42}, (_, index) => ({
    x: (index * 173 + 41) % 1920,
    y: (index * 97 + 63) % 1080,
    size: .8 + (index % 3) * .55,
  }));
  return <>
    <div style={{position: 'absolute', inset: 0, background: `radial-gradient(circle at ${20 + Math.sin(phase) * 3}% ${24 + Math.cos(phase) * 2}%, rgba(77,124,255,.14), transparent 31%), radial-gradient(circle at ${82 + Math.cos(phase) * 3}% ${68 + Math.sin(phase * 2) * 2}%, rgba(53,228,242,.11), transparent 33%), linear-gradient(145deg, ${C.bg}, ${C.bg2} 52%, #030711)`}}/>
    <div style={{position: 'absolute', inset: 0, opacity: .105, backgroundImage: 'linear-gradient(rgba(90,133,170,.11) 1px, transparent 1px), linear-gradient(90deg, rgba(90,133,170,.11) 1px, transparent 1px)', backgroundSize: '64px 64px', transform: `translate(${Math.sin(phase) * 8}px, ${Math.cos(phase) * 6}px)`}}/>
    <div style={{position: 'absolute', inset: 0, opacity: .028, backgroundImage: 'repeating-linear-gradient(0deg, rgba(255,255,255,.25) 0, rgba(255,255,255,.25) 1px, transparent 1px, transparent 3px)', mixBlendMode: 'soft-light'}}/>
    {dots.map((dot, index) => <div key={index} style={{position: 'absolute', left: dot.x + Math.sin(phase + index) * 5, top: dot.y + Math.cos(phase * 1.2 + index) * 4, width: dot.size, height: dot.size, borderRadius: dot.size, background: index % 5 === 0 ? C.cyan : '#a9c3dc', opacity: .07 + (index % 5) * .018 + Math.sin(phase * 2 + index) * .02, boxShadow: index % 5 === 0 ? `0 0 7px ${C.cyan}` : 'none'}}/>)}
  </>;
};

export const Motion: React.FC = () => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();
  const timeline = (frame / durationInFrames) * 900;
  const phase = (frame / durationInFrames) * Math.PI * 2;
  const master = lifecycle(timeline, 0, 55, 848, 900);
  const cameraX = Math.sin(phase) * 5 + Math.sin(phase * 2 + .5) * 1.5;
  const cameraY = Math.sin(phase * 2 - .2) * 3;
  const rotateX = Math.sin(phase + .6) * .12;
  const rotateY = Math.cos(phase) * .19;
  const scale = .989 + Math.sin(phase - .3) * .002;
  return (
    <AbsoluteFill style={{overflow: 'hidden', backgroundColor: C.bg}}>
      <Ambient phase={phase}/>
      <div style={{position: 'absolute', inset: 0, opacity: master, transform: `perspective(4200px) translate3d(${cameraX}px, ${cameraY}px, 0) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale(${scale * (.988 + master * .012)})`, transformOrigin: '50% 50%', transformStyle: 'preserve-3d', willChange: 'transform, opacity'}}>
        <Header timeline={timeline} phase={phase}/>
        <FxGlobe timeline={timeline} phase={phase}/>
        <RegionalPanel timeline={timeline} phase={phase}/>
        <LiquidityTimeline timeline={timeline} phase={phase}/>
      </div>
    </AbsoluteFill>
  );
};
